def parse_monto(raw):
    s = str(raw).strip().replace(',', '.')
    try:
        n = float(s)
    except ValueError:
        raise ValueError(f"monto no numérico: raw={raw!r}")
    if n < 0:
        raise ValueError(f"monto negativo: raw={raw!r}")
    return n

for v in ["10.5", "3,25", "abc", "-1"]:
    try:
        print(v, "->", parse_monto(v))
    except ValueError as e:
        print(v, "ERR", e)

