def bad_title(s: str) -> str:
    return s.title()

def good_title(s: str) -> str:
    parts = s.split()
    out = []
    for i, w in enumerate(parts):
        if i > 0 and w.lower() in {"de", "del", "la", "los", "las"}:
            out.append(w.lower())
        else:
            out.append(w.capitalize())
    return " ".join(out)

def test(fn):
    out = fn("juan de la cruz")
    assert out == "Juan de la Cruz", out
    return "pass"

try:
    test(bad_title)
except AssertionError as e:
    print("RED", e)
print("GREEN", test(good_title))

