def process_batch(rows):
    ok, quarantined = [], []
    for r in rows:
        if not r.get("id"):
            quarantined.append({"row": r, "reason": "missing id"})
        else:
            ok.append(r)
    return {"ok": ok, "quarantined": quarantined, "in": len(rows)}

rows = [{"id": 1}, {}, {"id": 2}]
print(process_batch(rows))

